import{_ as a,v as n,f as e,i as p}from"./chunks/framework.jfF5glnW.js";const u=JSON.parse('{"title":"期末 Hackathon | ESP32-S2 Mini 智能灯光与表情交互系统","description":"基于 ESP32-S2 Mini 的期末 Hackathon 项目，整合网页控制、语音识别、光敏检测、OLED 显示和双舵机执行，完成一个小型智能灯光交互系统。","frontmatter":{"title":"期末 Hackathon | ESP32-S2 Mini 智能灯光与表情交互系统","date":"2026-05-31T00:00:00.000Z","tags":["期末项目","Hackathon","ESP32","舵机","OLED"],"cover":"/code2real_blog/posts/final/1.jpg","description":"基于 ESP32-S2 Mini 的期末 Hackathon 项目，整合网页控制、语音识别、光敏检测、OLED 显示和双舵机执行，完成一个小型智能灯光交互系统。"},"headers":[],"relativePath":"posts/期末项目.md","filePath":"posts/期末项目.md"}'),l={name:"posts/期末项目.md"};function t(r,s,o,i,c,d){return n(),e("div",null,[...s[0]||(s[0]=[p(`<img src="/code2real_blog/posts/final/1.jpg" alt="Week 3 image"><p>本次期末 Hackathon 项目基于 <code>F:\\code_to_real\\end\\test1</code> 工程完成，主控为 ESP32-S2 Mini。项目目标是做一个小型智能灯光交互系统：网页和语音都可以控制双舵机动作，光敏模块自动控制 LED，OLED 根据环境状态显示表情或时间。</p><p>整体思路不是单独做一个网页控制舵机，也不是只做一个光敏灯，而是把网页控制、语音识别、光照检测、OLED 显示和双舵机动作整合到同一块 ESP32-S2 Mini 上。这样更接近一个完整的小作品，也更容易暴露嵌入式项目中常见的供电、接线、串口和交互问题。</p><h3 id="step1-项目选题与目标确定" tabindex="-1">step1 项目选题与目标确定 <a class="header-anchor" href="#step1-项目选题与目标确定" aria-label="Permalink to &quot;step1 项目选题与目标确定&quot;">​</a></h3><p>期末项目最初的方向是“智能开关灯”。如果只用按钮或网页控制 LED，功能过于简单；如果完全依赖语音模块直接控制舵机，又很难统一调试。因此最终把 ESP32 放在系统中心，让它同时接收网页指令和 ASRPRO 语音识别结果，再统一控制舵机动作。</p><p>项目目标分为四部分：</p><ul><li>网页端可以控制开灯、关灯、开左灯、开右灯等动作。</li><li>ASRPRO 语音模块可以通过串口发送识别 ID。</li><li>光敏模块根据环境明暗自动控制 LED。</li><li>OLED 显示表情或时钟，作为系统状态反馈。</li></ul><p>这个设计的好处是每个模块都有明确职责：网页负责远程控制，语音模块负责自然交互，光敏模块负责环境感知，OLED 负责可视化反馈，双舵机负责执行动作。</p><h2 id="step2-硬件方案设计" tabindex="-1">step2 硬件方案设计 <a class="header-anchor" href="#step2-硬件方案设计" aria-label="Permalink to &quot;step2 硬件方案设计&quot;">​</a></h2><p>硬件使用 ESP32-S2 Mini 作为主控，外接两个 SG90 舵机、一个 LED、四脚光敏模块、ASRPRO 语音识别模块、SSD1315/SSD1306 兼容 OLED，以及一个显示切换按钮。</p><p>主要接线如下：</p><table tabindex="0"><thead><tr><th>模块</th><th style="text-align:right;">ESP32-S2 Mini 引脚</th></tr></thead><tbody><tr><td>左舵机信号线</td><td style="text-align:right;">GPIO7</td></tr><tr><td>右舵机信号线</td><td style="text-align:right;">GPIO8</td></tr><tr><td>LED</td><td style="text-align:right;">GPIO9</td></tr><tr><td>光敏模块 AO</td><td style="text-align:right;">GPIO1</td></tr><tr><td>光敏模块 DO</td><td style="text-align:right;">GPIO10</td></tr><tr><td>显示切换按钮</td><td style="text-align:right;">GPIO12</td></tr><tr><td>ASRPRO TX</td><td style="text-align:right;">GPIO16</td></tr><tr><td>ASRPRO RX</td><td style="text-align:right;">GPIO17</td></tr><tr><td>OLED SDA</td><td style="text-align:right;">GPIO33</td></tr><tr><td>OLED SCL</td><td style="text-align:right;">GPIO35</td></tr></tbody></table><p>舵机供电是硬件部分最需要注意的地方。两个 SG90 同时动作时电流波动比较明显，如果直接从 ESP32 板子取电，容易造成复位或舵机抖动。</p><h2 id="step3-第一版-先做-esp32-s2-mini-基础原型" tabindex="-1">step3 第一版：先做 ESP32-S2 Mini 基础原型 <a class="header-anchor" href="#step3-第一版-先做-esp32-s2-mini-基础原型" aria-label="Permalink to &quot;step3 第一版：先做 ESP32-S2 Mini 基础原型&quot;">​</a></h2><p>开发不是一开始就完成最终版本，而是先做一个能跑的 ESP32-S2 Mini 原型。第一版目标比较直接：ESP32 连接 WiFi，网页控制一个 SG90 舵机，光敏电阻控制 LED，OLED 显示“高兴”和“困了”的表情。</p><p>这个阶段先选定了几个基础库：</p><div class="language-cpp line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#D73A49;">#include</span><span style="color:#032F62;"> &lt;ESP32Servo.h&gt;</span></span>
<span class="line"><span style="color:#D73A49;">#include</span><span style="color:#032F62;"> &lt;U8g2lib.h&gt;</span></span>
<span class="line"><span style="color:#D73A49;">#include</span><span style="color:#032F62;"> &lt;WebServer.h&gt;</span></span>
<span class="line"><span style="color:#D73A49;">#include</span><span style="color:#032F62;"> &lt;WiFi.h&gt;</span></span>
<span class="line"><span style="color:#D73A49;">#include</span><span style="color:#032F62;"> &lt;Wire.h&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>最初的思路是先把“网页控制舵机”和“光敏 LED”跑通，再慢慢加 OLED 表情。这样做的原因很简单：如果一上来就把网页、语音、屏幕、双舵机全部塞进去，出问题时很难判断是哪一层坏了。</p><h2 id="step4-第二版-发现需要两个舵机-改成左右控制" tabindex="-1">step4 第二版：发现需要两个舵机，改成左右控制 <a class="header-anchor" href="#step4-第二版-发现需要两个舵机-改成左右控制" aria-label="Permalink to &quot;step4 第二版：发现需要两个舵机，改成左右控制&quot;">​</a></h2><p>第一版只考虑了一个 SG90，但宿舍里有两片，需要两个舵机，分别控制左边和右边。因此第二步把单舵机结构改成双舵机结构。</p><p>代码里从一个 <code>Servo</code> 扩展成两个对象：</p><div class="language-cpp line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#24292E;">Servo leftServo;</span></span>
<span class="line"><span style="color:#24292E;">Servo rightServo;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>接线也随之确定：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span>左舵机信号线 -&gt; GPIO7</span></span>
<span class="line"><span>右舵机信号线 -&gt; GPIO8</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这一阶段网页还保留调试性质，使用左右两个角度控制入口，方便观察两个舵机是否能独立转动。调试时最容易出现的问题是左右方向反了，解决方式不是马上重接线，而是先调整代码顶部的角度常量。</p><p>解决后的表现是：左舵机和右舵机可以分别响应，串口输出也能看到两个舵机的角度状态。到这一步，项目从“单执行机构”变成了“双执行机构”。</p><h2 id="step5-重新检查光敏电阻-从裸-5516-到四脚模块" tabindex="-1">step5 重新检查光敏电阻：从裸 5516 到四脚模块 <a class="header-anchor" href="#step5-重新检查光敏电阻-从裸-5516-到四脚模块" aria-label="Permalink to &quot;step5 重新检查光敏电阻：从裸 5516 到四脚模块&quot;">​</a></h2><p>最开始光敏部分按裸 5516 分压电阻理解。后来检查后发现，实际使用的是四脚光敏模块，不是单独一颗光敏电阻。四脚模块通常带 LM393 比较器，有 <code>VCC/GND/AO/DO</code> 四个引脚。</p><p>这就解释了前期 LED 经常闪动、光敏模块看起来“没作用”的问题：程序按模拟量阈值判断，但实际接线和模块输出可能更适合用 DO 数字口。</p><p>后续接线改成：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span>光敏模块 VCC -&gt; 3.3V</span></span>
<span class="line"><span>光敏模块 GND -&gt; GND</span></span>
<span class="line"><span>光敏模块 AO  -&gt; GPIO1</span></span>
<span class="line"><span>光敏模块 DO  -&gt; GPIO10</span></span>
<span class="line"><span>LED          -&gt; GPIO9</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>程序默认优先使用 DO：</p><div class="language-cpp line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#D73A49;">const</span><span style="color:#D73A49;"> bool</span><span style="color:#24292E;"> USE_LIGHT_DIGITAL_OUTPUT </span><span style="color:#D73A49;">=</span><span style="color:#005CC5;"> true</span><span style="color:#24292E;">;</span></span>
<span class="line"><span style="color:#D73A49;">const</span><span style="color:#D73A49;"> bool</span><span style="color:#24292E;"> LIGHT_DIGITAL_ACTIVE_LOW </span><span style="color:#D73A49;">=</span><span style="color:#005CC5;"> false</span><span style="color:#24292E;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>同时加入连续读取过滤：</p><div class="language-cpp line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#D73A49;">const</span><span style="color:#D73A49;"> int</span><span style="color:#24292E;"> LIGHT_STABLE_READS </span><span style="color:#D73A49;">=</span><span style="color:#005CC5;"> 4</span><span style="color:#24292E;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>解决后的表现是：遮住光敏模块时，LED 能稳定点亮；移开光照后，LED 能稳定熄灭；在临界光线下不会一直闪。</p><h2 id="step6-加入网页控制说明-esp32-网页服务器" tabindex="-1">step6 加入网页控制说明：ESP32 网页服务器 <a class="header-anchor" href="#step6-加入网页控制说明-esp32-网页服务器" aria-label="Permalink to &quot;step6 加入网页控制说明：ESP32 网页服务器&quot;">​</a></h2><p>光敏部分稳定后，继续确认网页控制逻辑。ESP32 连接 WiFi 后，在本地开启 <code>WebServer server(80)</code>，手机或电脑只要和 ESP32 在同一个 WiFi 下，就能访问串口打印出的地址。</p><p>串口正常输出类似：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span> http://192.168.79.247</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="step7-讨论-asrpro-先确认它不能和-esp32-抢舵机" tabindex="-1">step7 讨论 ASRPRO：先确认它不能和 ESP32 抢舵机 <a class="header-anchor" href="#step7-讨论-asrpro-先确认它不能和-esp32-抢舵机" aria-label="Permalink to &quot;step7 讨论 ASRPRO：先确认它不能和 ESP32 抢舵机&quot;">​</a></h2><p>后续加入 ASRPRO 语音模块时，ASRPRO 和 ESP32 如果同时给同一个舵机发 PWM，舵机就会抖动。因此最终确定原则：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span>ASRPRO 只负责识别语音</span></span>
<span class="line"><span>ESP32 负责唯一控制舵机</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>也就是说，ASRPRO 不接舵机信号线，只通过串口把识别结果发给 ESP32。舵机仍然接在 ESP32 上，这样网页控制和语音控制可以共存。</p><h2 id="step8-esp32-解析语音-id-网页和语音共用动作" tabindex="-1">step8 ESP32 解析语音 ID：网页和语音共用动作 <a class="header-anchor" href="#step8-esp32-解析语音-id-网页和语音共用动作" aria-label="Permalink to &quot;step8 ESP32 解析语音 ID：网页和语音共用动作&quot;">​</a></h2><p>ESP32 端新增 <code>HardwareSerial asrSerial(1)</code>，专门接收 ASRPRO 串口数据。程序使用 <code>parseAsrId()</code> 从字符串中提取数字，因此不仅能识别 <code>3</code>，也能识别 <code>ID=3</code> 这类格式。</p><p>语音动作和网页动作最后都进入同一个函数：</p><div class="language-cpp line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#D73A49;">bool</span><span style="color:#6F42C1;"> runServoAction</span><span style="color:#24292E;">(</span><span style="color:#D73A49;">int</span><span style="color:#E36209;"> id</span><span style="color:#24292E;">) {</span></span>
<span class="line"><span style="color:#D73A49;">  switch</span><span style="color:#24292E;"> (id) {</span></span>
<span class="line"><span style="color:#D73A49;">    case</span><span style="color:#005CC5;"> 1</span><span style="color:#24292E;">:</span></span>
<span class="line"><span style="color:#6F42C1;">      tapBothServos</span><span style="color:#24292E;">(LEFT_SERVO_ON_ANGLE, RIGHT_SERVO_ON_ANGLE);</span></span>
<span class="line"><span style="color:#D73A49;">      return</span><span style="color:#005CC5;"> true</span><span style="color:#24292E;">;</span></span>
<span class="line"><span style="color:#D73A49;">    case</span><span style="color:#005CC5;"> 2</span><span style="color:#24292E;">:</span></span>
<span class="line"><span style="color:#6F42C1;">      tapBothServos</span><span style="color:#24292E;">(LEFT_SERVO_OFF_ANGLE, RIGHT_SERVO_OFF_ANGLE);</span></span>
<span class="line"><span style="color:#D73A49;">      return</span><span style="color:#005CC5;"> true</span><span style="color:#24292E;">;</span></span>
<span class="line"><span style="color:#D73A49;">    case</span><span style="color:#005CC5;"> 3</span><span style="color:#24292E;">:</span></span>
<span class="line"><span style="color:#6F42C1;">      tapLeftServo</span><span style="color:#24292E;">(LEFT_SERVO_ON_ANGLE);</span></span>
<span class="line"><span style="color:#D73A49;">      return</span><span style="color:#005CC5;"> true</span><span style="color:#24292E;">;</span></span>
<span class="line"><span style="color:#D73A49;">    case</span><span style="color:#005CC5;"> 4</span><span style="color:#24292E;">:</span></span>
<span class="line"><span style="color:#6F42C1;">      tapRightServo</span><span style="color:#24292E;">(RIGHT_SERVO_ON_ANGLE);</span></span>
<span class="line"><span style="color:#D73A49;">      return</span><span style="color:#005CC5;"> true</span><span style="color:#24292E;">;</span></span>
<span class="line"><span style="color:#D73A49;">    case</span><span style="color:#005CC5;"> 5</span><span style="color:#24292E;">:</span></span>
<span class="line"><span style="color:#6F42C1;">      tapRightServo</span><span style="color:#24292E;">(RIGHT_SERVO_OFF_ANGLE);</span></span>
<span class="line"><span style="color:#D73A49;">      return</span><span style="color:#005CC5;"> true</span><span style="color:#24292E;">;</span></span>
<span class="line"><span style="color:#D73A49;">    case</span><span style="color:#005CC5;"> 6</span><span style="color:#24292E;">:</span></span>
<span class="line"><span style="color:#6F42C1;">      tapLeftServo</span><span style="color:#24292E;">(LEFT_SERVO_OFF_ANGLE);</span></span>
<span class="line"><span style="color:#D73A49;">      return</span><span style="color:#005CC5;"> true</span><span style="color:#24292E;">;</span></span>
<span class="line"><span style="color:#D73A49;">    default</span><span style="color:#24292E;">:</span></span>
<span class="line"><span style="color:#D73A49;">      return</span><span style="color:#005CC5;"> false</span><span style="color:#24292E;">;</span></span>
<span class="line"><span style="color:#24292E;">  }</span></span>
<span class="line"><span style="color:#24292E;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br></div></div><p>这里还处理了一个细节：ASRPRO 有时输出没有换行。如果程序只等 <code>\\n</code>，命令可能不会执行。因此加入 <code>ASR_LINE_TIMEOUT_MS</code>，收到字符后一小段时间没有新字符，也会尝试解析。</p><p>解决后的表现是：网页按钮和语音命令触发的是同一套舵机动作，后续维护只需要改一个动作函数。</p><h2 id="step9-oled-显示调整-复杂颜文字显示不全" tabindex="-1">step9 OLED 显示调整：复杂颜文字显示不全 <a class="header-anchor" href="#step9-oled-显示调整-复杂颜文字显示不全" aria-label="Permalink to &quot;step9 OLED 显示调整：复杂颜文字显示不全&quot;">​</a></h2><p>后来尝试把开心表情换成 <code>ヾ(≧▽≦*)o</code>，但实际显示不全。问题主要有两个：一是 128 像素宽度不够，二是 U8g2 字体对复杂字符支持有限。</p><p>解决方式是换成更适合 OLED 的 ASCII 表情：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span>(^///^)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>最终 OLED 逻辑确定为：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span>亮 / LED 灭：(^///^)</span></span>
<span class="line"><span>暗 / LED 亮：-_- zZ</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这一版牺牲了一点花哨程度，但稳定显示更重要。</p><h2 id="step10-加入按钮切换时钟模块" tabindex="-1">step10 加入按钮切换时钟模块 <a class="header-anchor" href="#step10-加入按钮切换时钟模块" aria-label="Permalink to &quot;step10 加入按钮切换时钟模块&quot;">​</a></h2><p>在表情显示稳定后，又加入了一个按钮切换的时钟模块。按钮接在 GPIO12，采用 <code>INPUT_PULLUP</code>：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span>GPIO12 -&gt; 按钮 -&gt; GND</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>显示模式变成两种：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span>DISPLAY_FACE</span></span>
<span class="line"><span>DISPLAY_CLOCK</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>默认是光敏表情模式，按一下按钮切到时钟模式，再按一下切回表情模式。时钟来自 WiFi/NTP。</p><h2 id="step11-当前完成效果" tabindex="-1">step11 当前完成效果 <a class="header-anchor" href="#step11-当前完成效果" aria-label="Permalink to &quot;step11 当前完成效果&quot;">​</a></h2><p>截至期末 Hackathon 阶段，项目已经完成以下功能：</p><ul><li>ESP32-S2 Mini 成功连接 WiFi，并开启网页控制面板。</li><li>网页按钮可以控制两个舵机完成开灯、关灯等动作。</li><li>ASRPRO 可以通过串口 ID 触发同一套舵机动作。</li><li>光敏模块可以根据环境明暗自动控制 LED。</li><li>OLED 可以显示 <code>(^///^)</code> 和 <code>-_- zZ</code>，也可以通过按钮切换到时钟页面。</li><li>串口能持续输出光敏值、LED 状态、舵机角度和当前状态。</li></ul><h2 id="step12-sw-画外壳建模" tabindex="-1">step12 SW 画外壳建模 <a class="header-anchor" href="#step12-sw-画外壳建模" aria-label="Permalink to &quot;step12 SW 画外壳建模&quot;">​</a></h2><ul><li><strong><code>工具</code></strong> → <strong><code>草图工具</code></strong> → <strong><code>草图图片</code></strong>，选择图片插入。</li><li>点击<strong>下一步的箭头图标</strong>，鼠标悬停显示“<strong>跟踪设定</strong>”。</li><li>选择“矩形选择”，在图片上框选需要跟踪的区域。</li><li>调整对比度和颜色公差，控制轮廓识别的敏感度。</li><li>确保轮廓都是<strong>闭合的</strong>。</li><li>使用 <strong><code>插入</code></strong> → <strong><code>特征</code></strong> → <strong><code>包覆</code></strong>，选择“浮雕/蚀雕”，指定面并输入深度。</li></ul><h2 id="step13-题外话-gpt-sovits" tabindex="-1">step13 题外话：GPT-SoVITS <a class="header-anchor" href="#step13-题外话-gpt-sovits" aria-label="Permalink to &quot;step13 题外话：GPT-SoVITS&quot;">​</a></h2><p>用 GPT-SoVITS v3 合成爱丽丝的活全家语音，其中一部分截取了游戏语音。</p><p><strong>Contributor:</strong></p><ul><li><a href="https://www.yuque.com/baicaigongchang1145haoyuangong/ib3g1e" target="_blank" rel="noreferrer">https://www.yuque.com/baicaigongchang1145haoyuangong/ib3g1e</a></li><li><a href="https://www.bilibili.com/video/BV1bx4y1y7sX/?spm_id_from=333.337.search-card.all.click&amp;vd_source=e3704f9074fe56732909b4abd8186319" target="_blank" rel="noreferrer">https://www.bilibili.com/video/BV1bx4y1y7sX/?spm_id_from=333.337.search-card.all.click&amp;vd_source=e3704f9074fe56732909b4abd8186319</a></li><li><a href="https://kivo.wiki/" target="_blank" rel="noreferrer">https://kivo.wiki/</a></li></ul><h2 id="step14-项目总结" tabindex="-1">step14 项目总结 <a class="header-anchor" href="#step14-项目总结" aria-label="Permalink to &quot;step14 项目总结&quot;">​</a></h2><p>这个期末项目不是一次写完的，而是按问题一步步推进出来的。先做 ESP32 基础原型，再改双舵机；中间改过 ESP8266，又回到真实板卡；光敏部分从裸 5516 思路改成四脚模块逻辑；ASRPRO 从“直接控制舵机”改成“只发识别 ID”；OLED 从圆脸改成稳定颜文字；网页最后也从调试滑条收紧成动作按钮。</p><p>最终方案采用 ESP32 作为统一控制中心。网页和语音只负责发送动作 ID，舵机动作统一由 <code>runServoAction()</code> 执行；光敏模块独立决定 LED 状态；OLED 负责表情和时钟反馈。这样系统结构比较清楚，也便于后续维护。</p><p>从 Hackathon 结果看，项目已经达到期末展示要求。它不是单一传感器实验，而是一个经过多轮修正后形成的小型嵌入式交互系统。</p>`,76)])])}const h=a(l,[["render",t]]);export{u as __pageData,h as default};
